164→
165→export const generateSchemaWithAI = async (data: SchemaInput): Promise<SchemaResult> => {
166→  const apiKey = getApiKey();
167→
168→  if (!apiKey) {
169→    console.warn("API_KEY not found, using local Schema.org generation.");
170→    return fallbackGeneration(data);
171→  }
172→
173→  try {
174→    const ai = new GoogleGenAI({ apiKey });
175→
176→    const schema: Schema = {
177→      type: Type.OBJECT,
178→      properties: {
179→        jsonLd: { type: Type.STRING, description: "The complete JSON-LD Schema.org markup as a stringified JSON object" },
180→        typesCount: { type: Type.NUMBER, description: "Number of @type entries in the @graph array" },
181→        byteSize: { type: Type.NUMBER, description: "Approximate byte size of the JSON-LD content" },
182→      },
183→      required: ["jsonLd", "typesCount", "byteSize"],
184→    };
185→
186→    const socialProfilesDesc = data.socialProfiles
187→      .filter(url => url.length > 0)
188→      .map(url => `- ${url}`)
189→      .join('\n');
190→
191→    const prompt = `
192→      INFORMATIONS DE L'ENTITE :
193→      - Nom : ${data.name}
194→      ${data.alternateName ? `- Nom alternatif : ${data.alternateName}` : ''}
195→      - URL : ${data.url}
196→      - Description : ${data.description}
197→      - Logo URL : ${data.logoUrl}
198→
199→      CONTACT :
200→      ${data.contactEmail ? `- Email : ${data.contactEmail}` : ''}
201→      ${data.contactPhone ? `- Telephone : ${data.contactPhone}` : ''}
202→
203→      ${socialProfilesDesc ? `PROFILS SOCIAUX (sameAs — critiques pour la desambiguation) :\n${socialProfilesDesc}` : 'PROFILS SOCIAUX : Aucun renseigne'}
204→
205→      MISSION :
206→      Genere un balisage JSON-LD Schema.org complet et optimise pour maximiser la visibilite dans le Knowledge Graph de Google et la citabilite par les moteurs de reponse IA.
207→
208→      Le balisage doit inclure au minimum :
209→      - Organization avec @id, name, url, logo (ImageObject), description, sameAs, contactPoint
210→      - WebSite avec @id, name, url, publisher (reference Organization), potentialAction (SearchAction)
211→      - WebPage pour la page d'accueil avec @id, name, url, isPartOf (WebSite), about (Organization)
212→
213→      Enrichis le balisage avec toutes les proprietes Schema.org pertinentes basees sur les informations fournies.
214→      Assure-toi que chaque entite a un @id canonique unique et que les references entre entites sont correctes.
215→
216→      Le champ "jsonLd" de ta reponse doit contenir le JSON-LD complet stringify.
217→      Calcule typesCount (nombre d'entites dans @graph) et byteSize (taille approximative en octets).
218→    `;
219→
220→    const response = await ai.models.generateContent({
221→      model: 'gemini-2.5-flash',
222→      contents: prompt,
223→      config: {
224→        systemInstruction: SCHEMA_SYSTEM_PROMPT,
225→        responseMimeType: 'application/json',
226→        responseSchema: schema,
227→        temperature: 0.2,
228→      },
229→    });
230→
231→    let output = response.text;
232→    if (!output) {
233→      throw new Error("Empty response from AI");
234→    }
235→
236→    output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
237→    const parsed = JSON.parse(output);
238→
239→    // Try to pretty-print the inner JSON if it was stringified
240→    let content = parsed.jsonLd;
241→    try {
242→      const innerJson = JSON.parse(content);
243→      content = JSON.stringify(innerJson, null, 2);
244→    } catch {
245→      // Already a string or not valid JSON, keep as-is
246→    }
247→
248→    return {
249→      content,
250→      typesCount: parsed.typesCount,
251→      byteSize: parsed.byteSize,
252→    };
253→  } catch (error) {
254→    console.error("Schema.org AI generation failed:", error);
255→    return fallbackGeneration(data);
256→  }
257→};
