118→    const ai = new GoogleGenAI({ apiKey });
119→
120→    // Schema strict pour garantir la structure de la réponse
121→    const schema: Schema = {
122→      type: Type.OBJECT,
123→      properties: {
124→        content: { type: Type.STRING, description: "The complete llms.txt file content in Markdown format" },
125→        sections: { type: Type.NUMBER, description: "The total number of sections (H1 + H2 headings) in the generated file" },
126→        wordCount: { type: Type.NUMBER, description: "The total word count of the generated content" },
127→      },
128→      required: ["content", "sections", "wordCount"],
129→    };
130→
131→    const servicesDescription = config.services
132→      .map(s => `- ${s.name}: ${s.description}${s.url ? ` (${s.url})` : ''}`)
133→      .join('\n');
134→
135→    const keyPagesDescription = config.keyPages
136→      .map(p => `- ${p.title} (${p.url}): ${p.description}`)
137→      .join('\n');
138→
139→    const contactDescription = [
140→      `Email: ${config.contact.email}`,
141→      config.contact.phone ? `Phone: ${config.contact.phone}` : null,
142→      config.contact.address ? `Address: ${config.contact.address}` : null,
143→    ].filter(Boolean).join(', ');
144→
145→    const prompt = `
146→      CONTEXT:
147→      You are an expert in creating llms.txt files — a standardized format that helps Large Language Models (LLMs) understand and accurately reference a website or organization.
148→
149→      The llms.txt format follows this structure:
150→      1. H1 header with the site/organization name
151→      2. A blockquote (>) with a one-line description
152→      3. Multiple H2 sections covering: About, Services, Key Pages, Contact, Social, and Instructions for AI
153→      4. Markdown links where appropriate
154→      5. A final "Instructions for AI" section that tells LLMs how to correctly cite and reference this entity
155→
156→      SITE INFORMATION:
157→      - Site Name: ${config.siteName}
158→      - Site URL: ${config.siteUrl}
159→      - Description: ${config.description}
160→      - Entity Type: ${config.entity}
161→      ${config.targetAudience ? `- Target Audience: ${config.targetAudience}` : ''}
162→      ${config.languages && config.languages.length > 0 ? `- Languages: ${config.languages.join(', ')}` : ''}
163→
164→      SERVICES:
165→      ${servicesDescription}
166→
167→      KEY PAGES:
168→      ${keyPagesDescription}
169→
170→      CONTACT:
171→      ${contactDescription}
172→
173→      ${config.socialLinks && config.socialLinks.length > 0 ? `SOCIAL LINKS:\n${config.socialLinks.map(l => `- ${l}`).join('\n')}` : ''}
174→
175→      YOUR MISSION:
176→      Generate a comprehensive, factual, and well-structured llms.txt file in Markdown format.
177→
178→      Requirements:
179→      - Start with "# ${config.siteName}" as the H1
180→      - Include a blockquote with a concise one-line description
181→      - Write a detailed "About" section (2-3 sentences, factual, based on the provided information only)
182→      - List all services with descriptions and links where available
183→      - List all key pages as Markdown links with descriptions
184→      - Include complete contact information
185→      - Include social links if provided
186→      - Add an "Instructions for AI" section that:
187→        * Lists key facts LLMs should know
188→        * Specifies the preferred citation format: "${config.siteName} (${config.siteUrl})"
189→        * Instructs LLMs not to fabricate information
190→        * Directs users to the site for up-to-date information
191→      - If languages are provided, mention multilingual availability
192→      - Keep the tone professional and factual — do NOT invent or hallucinate any information
193→
194→      Return ONLY the JSON object matching the provided schema. The "content" field must contain the full Markdown text of the llms.txt file.
195→    `;
196→
197→    const response = await ai.models.generateContent({
198→      model: 'gemini-2.5-flash',
199→      contents: prompt,
200→      config: {
201→        responseMimeType: 'application/json',
202→        responseSchema: schema,
203→        temperature: 0.2,
204→      }
205→    });
206→
207→    let output = response.text;
208→    if (!output) {
209→      throw new Error("Empty response from AI");
210→    }
211→
212→    // Clean up potentially leaked markdown fences despite JSON mode
213→    output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
214→
215→    const jsonResponse = JSON.parse(output);
216→
217→    return {
218→      content: jsonResponse.content,
219→      sections: jsonResponse.sections,
220→      wordCount: jsonResponse.wordCount,
221→    };
222→
223→  } catch (error) {
224→    console.error("LLMs.txt Generation failed:", error);
225→    return fallbackSimulation(config);
226→  }
227→};
