  9→const STORAGE_KEY = 'citedby-eeat-history';
 10→
 11→export interface EeatAuditHistoryEntry {
 12→  id: string;
 13→  url: string;
 14→  brand?: string;
 15→  date: string;
 16→  scores: EeatAuditResult['scores'];
 17→  findings: EeatAuditResult['findings'];
 18→  priorityActions: EeatAuditResult['priorityActions'];
 19→  summary: string;
 20→}
 21→
 22→export interface AuditComparison {
 23→  current: EeatAuditHistoryEntry;
 24→  previous: EeatAuditHistoryEntry;
 25→  deltas: {
 26→    overall: number;
 27→    experience: number;
 28→    expertise: number;
 29→    authoritativeness: number;
 30→    trustworthiness: number;
 31→  };
 32→  improvedCount: number;
 33→  regressedCount: number;
 34→}
 35→
 36→export const saveAuditToHistory = (result: EeatAuditResult, brand?: string): EeatAuditHistoryEntry => {
 37→  const history = getAuditHistory();
 38→  const entry: EeatAuditHistoryEntry = {
 39→    id: `audit-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
 40→    url: result.url,
 41→    brand,
 42→    date: new Date().toISOString(),
 43→    scores: { ...result.scores },
 44→    findings: [...result.findings],
 45→    priorityActions: [...result.priorityActions],
 46→    summary: result.summary,
 47→  };
 48→  history.unshift(entry);
 49→  // Keep max 50 entries
 50→  if (history.length > 50) history.length = 50;
 51→  try {
 52→    localStorage.setItem(STORAGE_KEY, JSON.stringify(history));
 53→  } catch (e) {
 54→    console.warn('Failed to save audit history to localStorage:', e);
 55→  }
 56→  return entry;
 57→};
 58→
 59→export const getAuditHistory = (): EeatAuditHistoryEntry[] => {
 60→  try {
 61→    const raw = localStorage.getItem(STORAGE_KEY);
 62→    if (!raw) return [];
 63→    return JSON.parse(raw) as EeatAuditHistoryEntry[];
 64→  } catch {
 65→    return [];
 66→  }
 67→};
 68→
 69→export const getLastAuditForUrl = (url: string): EeatAuditHistoryEntry | null => {
 70→  const history = getAuditHistory();
 71→  let hostname: string;
 72→  try { hostname = new URL(url).hostname; } catch { hostname = url; }
 73→  return history.find(h => {
 74→    try { return new URL(h.url).hostname === hostname; } catch { return h.url === url; }
 75→  }) || null;
 76→};
 77→
 78→export const compareAudits = (current: EeatAuditHistoryEntry, previous: EeatAuditHistoryEntry): AuditComparison => {
 79→  const deltas = {
 80→    overall: current.scores.overall - previous.scores.overall,
 81→    experience: current.scores.experience - previous.scores.experience,
 82→    expertise: current.scores.expertise - previous.scores.expertise,
 83→    authoritativeness: current.scores.authoritativeness - previous.scores.authoritativeness,
 84→    trustworthiness: current.scores.trustworthiness - previous.scores.trustworthiness,
 85→  };
 86→  const deltaValues = [deltas.experience, deltas.expertise, deltas.authoritativeness, deltas.trustworthiness];
 87→  return {
 88→    current,
 89→    previous,
 90→    deltas,
 91→    improvedCount: deltaValues.filter(d => d > 0).length,
 92→    regressedCount: deltaValues.filter(d => d < 0).length,
 93→  };
 94→};
