116→const fallbackSimulation = async (url: string, brandName?: string): Promise<EeatAuditResult> => {
117→  await new Promise(resolve => setTimeout(resolve, 2800));
118→
119→  let hostname: string;
120→  try { hostname = new URL(url).hostname; } catch { hostname = url; }
121→  const brand = brandName || hostname;
122→  const seed = url.length + hostname.length;
123→
124→  const experience = seededScore(seed, 1);
125→  const expertise = seededScore(seed, 2);
126→  const authoritativeness = seededScore(seed, 3);
127→  const trustworthiness = seededScore(seed, 4);
128→  const overall = Math.round((experience + expertise + authoritativeness + trustworthiness) / 4);
129→
130→  const findings: EeatAuditResult['findings'] = [
131→    { category: 'experience', status: experience >= 50 ? 'present' : 'missing', element: 'Temoignages de premiere main', impact: 'high', recommendation: 'Ajouter des etudes de cas detaillees avec des resultats concrets et mesurables.' },
132→    { category: 'experience', status: experience >= 60 ? 'present' : 'incomplete', element: 'Contenu original (photos, videos)', impact: 'medium', recommendation: 'Integrer des visuels originaux (captures, photos terrain, videos) pour prouver l\'experience.' },
133→    { category: 'experience', status: experience >= 40 ? 'incomplete' : 'missing', element: 'Details specifiques au metier', impact: 'medium', recommendation: 'Enrichir le contenu avec des termes techniques et des details concrets du secteur.' },
134→    { category: 'expertise', status: expertise >= 50 ? 'present' : 'missing', element: 'Auteur identifie avec bio', impact: 'high', recommendation: 'Ajouter un bloc auteur avec bio, photo et credentials sur chaque article.' },
135→    { category: 'expertise', status: expertise >= 60 ? 'present' : 'missing', element: 'Credentials visibles', impact: 'high', recommendation: 'Lister les diplomes, certifications et experiences directement sur la page.' },
136→    { category: 'expertise', status: expertise >= 40 ? 'incomplete' : 'missing', element: 'Schema.org Person/hasCredential', impact: 'medium', recommendation: 'Implementer le schema JSON-LD Person avec hasCredential et alumniOf.' },
137→    { category: 'expertise', status: expertise >= 55 ? 'present' : 'incomplete', element: 'Profondeur du contenu', impact: 'medium', recommendation: 'Approfondir les sujets avec des donnees chiffrees, des sources et des exemples.' },
138→    { category: 'authority', status: authoritativeness >= 50 ? 'present' : 'missing', element: 'Mentions presse', impact: 'high', recommendation: 'Creer un bloc "Ils parlent de nous" avec des citations et liens vers les articles.' },
139→    { category: 'authority', status: authoritativeness >= 60 ? 'present' : 'missing', element: 'Citations par des pairs', impact: 'medium', recommendation: 'Obtenir des backlinks de sites d\'autorite et des mentions par des experts du secteur.' },
140→    { category: 'authority', status: authoritativeness >= 40 ? 'incomplete' : 'missing', element: 'Anciennete du domaine', impact: 'low', recommendation: 'Mettre en avant la date de creation du site et l\'historique de l\'entreprise.' },
141→    { category: 'trust', status: trustworthiness >= 60 ? 'present' : 'present', element: 'HTTPS', impact: 'high', recommendation: 'Le site est accessible en HTTPS (bon signal de confiance).' },
142→    { category: 'trust', status: trustworthiness >= 50 ? 'present' : 'missing', element: 'Mentions legales', impact: 'high', recommendation: 'Ajouter des mentions legales completes avec raison sociale, SIRET, adresse.' },
143→    { category: 'trust', status: trustworthiness >= 40 ? 'incomplete' : 'missing', element: 'Contact visible', impact: 'medium', recommendation: 'Afficher clairement email, telephone et adresse sur toutes les pages.' },
144→    { category: 'trust', status: trustworthiness >= 55 ? 'present' : 'missing', element: 'Avis verifiables', impact: 'high', recommendation: 'Integrer des avis Google/Trustpilot avec Schema.org AggregateRating.' },
145→    { category: 'trust', status: trustworthiness >= 45 ? 'incomplete' : 'missing', element: 'Politique de confidentialite', impact: 'medium', recommendation: 'Publier une politique de confidentialite detaillee et conforme RGPD.' },
146→  ];
147→
148→  const sortedFindings = [...findings].filter(f => f.status !== 'present').sort((a, b) => {
149→    const impactOrder = { high: 0, medium: 1, low: 2 };
150→    return impactOrder[a.impact] - impactOrder[b.impact];
151→  });
152→
153→  const priorityActions: EeatAuditResult['priorityActions'] = sortedFindings.slice(0, 5).map((f, i) => ({
154→    action: f.recommendation || `Ameliorer : ${f.element}`,
155→    impact: 100 - i * 15,
156→    effort: f.impact === 'high' ? 'medium' as const : 'low' as const,
157→    tool: f.category === 'expertise' ? 'Author Bio Generator' : f.category === 'authority' ? 'Trust Signals Generator' : f.category === 'trust' ? 'Trust Signals Generator' : 'Citation Block Generator',
158→  }));
159→
160→  const summary = overall >= 70
161→    ? `${brand} presente un bon profil E-E-A-T avec un score de ${overall}/100. Les signaux d'autorite et de confiance sont bien presents. Des ameliorations ciblees sur ${experience < expertise ? 'l\'experience documentee' : 'l\'expertise visible'} permettraient d'atteindre l'excellence.`
162→    : overall >= 45
163→      ? `${brand} a un profil E-E-A-T moyen (${overall}/100). Certains signaux sont presents mais des elements cles manquent. Priorite : renforcer les credentials des auteurs, ajouter des preuves sociales et structurer les donnees Schema.org.`
164→      : `${brand} a un faible score E-E-A-T (${overall}/100). Les moteurs de reponse IA ne trouvent pas suffisamment de signaux d'autorite et de confiance. Une strategie E-E-A-T complete est necessaire : bios auteurs, certifications, avis, mentions legales.`;
165→
166→  return {
167→    url,
168→    scores: { overall, experience, expertise, authoritativeness, trustworthiness },
169→    findings,
170→    priorityActions,
171→    summary,
172→  };
173→};
