175→const buildResponseSchema = (): Schema => {
176→  const findingSchema: Schema = {
177→    type: Type.OBJECT,
178→    properties: {
179→      category: { type: Type.STRING, description: "experience | expertise | authority | trust" },
180→      status: { type: Type.STRING, description: "present | missing | incomplete" },
181→      element: { type: Type.STRING, description: "Element E-E-A-T evalue" },
182→      impact: { type: Type.STRING, description: "high | medium | low" },
183→      recommendation: { type: Type.STRING, description: "Recommandation actionable" },
184→    },
185→    required: ["category", "status", "element", "impact"],
186→  };
187→
188→  const actionSchema: Schema = {
189→    type: Type.OBJECT,
190→    properties: {
191→      action: { type: Type.STRING },
192→      impact: { type: Type.NUMBER },
193→      effort: { type: Type.STRING, description: "low | medium | high" },
194→      tool: { type: Type.STRING, description: "Outil E-E-A-T recommande" },
195→    },
196→    required: ["action", "impact", "effort", "tool"],
197→  };
198→
199→  return {
200→    type: Type.OBJECT,
201→    properties: {
202→      scores: {
203→        type: Type.OBJECT,
204→        properties: {
205→          overall: { type: Type.NUMBER },
206→          experience: { type: Type.NUMBER },
207→          expertise: { type: Type.NUMBER },
208→          authoritativeness: { type: Type.NUMBER },
209→          trustworthiness: { type: Type.NUMBER },
210→        },
211→        required: ["overall", "experience", "expertise", "authoritativeness", "trustworthiness"],
212→      },
213→      findings: { type: Type.ARRAY, items: findingSchema },
214→      priorityActions: { type: Type.ARRAY, items: actionSchema },
215→      summary: { type: Type.STRING },
216→    },
217→    required: ["scores", "findings", "priorityActions", "summary"],
218→  };
219→};
