221→export const auditEeat = async (url: string, brandName?: string): Promise<EeatAuditResult> => {
222→  const apiKey = getApiKey();
223→  if (!apiKey) {
224→    console.warn("API_KEY not found, using simulation.");
225→    return fallbackSimulation(url, brandName);
226→  }
227→
228→  try {
229→    const ai = new GoogleGenAI({ apiKey });
230→
231→    const prompt = `${PROMPT_EEAT_AUDIT}\n\nURL: ${url}\n${brandName ? `MARQUE: ${brandName}` : ''}\n\nAnalyse la page et genere l'audit E-E-A-T complet.`;
232→
233→    const response = await ai.models.generateContent({
234→      model: 'gemini-2.5-flash',
235→      contents: prompt,
236→      config: {
237→        responseMimeType: 'application/json',
238→        responseSchema: buildResponseSchema(),
239→        temperature: 0.3,
240→      }
241→    });
242→
243→    let output = response.text;
244→    if (!output) throw new Error("Empty response");
245→    output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
246→
247→    const parsed = JSON.parse(output);
248→    return { url, ...parsed };
249→  } catch (error) {
250→    console.error("E-E-A-T Audit failed:", error);
251→    return fallbackSimulation(url, brandName);
252→  }
253→};
